245→		// errors (code 236). Retry the insert+read cycle with exponential backoff.
246→		let results: Awaited<ReturnType<typeof waitForRow>> = [];
247→		for (let attempt = 0; attempt < 5; attempt++) {
248→			try {
249→				await ingestSession(executor, input, {
250→					userId: "test_user",
251→					organizationId: "test_org",
252→				});
253→			} catch {
254→				await new Promise((r) => setTimeout(r, 2000 * 2 ** attempt));
